interface Identifiable {
  id: number;
  getDescription(): string;
}

class Produit implements Identifiable {
  // Raccourci constructeur : déclare + initialise en un coup
  constructor(
    public readonly id: number,
    public nom: string,
    private prix: number,
    protected categorie: string
  ) {}

  getDescription(): string {
    return `${this.nom} (${this.categorie})`;
  }

  getPrix(): number {
    return this.prix;
  }

  appliquerRemise(pourcentage: number): void {
    this.prix *= (1 - pourcentage / 100);
  }
}

const t = new Produit(1, 'T-shirt', 29.99, 'Vêtements');
console.log(t.getDescription()); // T-shirt (Vêtements)
